#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#define MAX_WORD_LEN 6
#define MAX_WORDS 500

void bfs(char *startWord, char *targetWord, char **wordList, int wordListSize) {
    int N = wordListSize;
    int M = strlen(startWord);
    bool visited[N];
    for (int i = 0; i < N; i++) {
        visited[i] = false;
    }
    int queueSize = 0;
    char **queue = (char **)malloc(N * sizeof(char *));
    for (int i = 0; i < N; i++) {
        queue[i] = (char *)malloc(MAX_WORD_LEN * sizeof(char));
    }
    strcpy(queue[queueSize++], startWord);
    visited[0] = true;
    int level = 0;
    while (queueSize > 0) {
        int levelSize = queueSize;
        for (int i = 0; i < levelSize; i++) {
            char *currentWord = queue[i - level];
            if (strcmp(currentWord, targetWord) == 0) {
                printf("%s", currentWord);
                return;
            }
            for (int j = 0; j < N; j++) {
                if (!visited[j]) {
                    char *word = wordList[j];
                    int diff = 0;
                    for (int k = 0; k < M; k++) {
                        if (currentWord[k] != word[k]) {
                            diff++;
                        }
                    }
                    if (diff == 1) {
                        strcpy(queue[queueSize], word);
                        queueSize++;
                        visited[j] = true;
                    }
                }
            }
        }
        level++;
    }
    printf("-1");
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char startWord[MAX_WORD_LEN], targetWord[MAX_WORD_LEN];
        scanf("%s %s", startWord, targetWord);
        int N;
        scanf("%d", &N);
        char **wordList = (char **)malloc(N * sizeof(char *));
        for (int i = 0; i < N; i++) {
            wordList[i] = (char *)malloc(MAX_WORD_LEN * sizeof(char));
            scanf("%s", wordList[i]);
        }
        bfs(startWord, targetWord, wordList, N);
        for (int i = 0; i < N; i++) {
            free(wordList[i]);
        }
        free(wordList);
    }
    return 0;
}

