#include <iostream>
#include <queue>
#include <unordered_set>
#include <unordered_map>
#include <string>
using namespace std;

void bfs(string startWord, string targetWord, vector<string> &wordList) {
    int N = wordList.size();
    int M = startWord.length();
    unordered_set<string> visited;
    queue<pair<string, vector<string>>> q;
    q.push({startWord, {startWord}});
    visited.insert(startWord);
    while (!q.empty()) {
        string currentWord = q.front().first;
        vector<string> path = q.front().second;
        q.pop();
        if (currentWord == targetWord) {
            for (const auto &word : path) {
                cout << word << " ";
            }
            cout << endl;
            return;
        }
        for (int i = 0; i < N; i++) {
            string word = wordList[i];
            if (visited.find(word) == visited.end()) {
                int diff = 0;
                for (int j = 0; j < M; j++) {
                    if (currentWord[j] != word[j]) {
                        diff++;
                    }
                }
                if (diff == 1) {
                    q.push({word, path});
                    q.back().second.push_back(word);
                    visited.insert(word);
                }
            }
        }
    }
    cout << -1;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        string startWord, targetWord;
        cin >> startWord >> targetWord;
        int N;
        cin >> N;
        vector<string> wordList(N);
        for (int i = 0; i < N; i++) {
            cin >> wordList[i];
        }
        bfs(startWord, targetWord, wordList);
    }
    return 0;
}

