import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.Queue;
import java.util.LinkedList;
import java.util.HashSet;
import java.util.HashMap;
import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void bfs(String startWord, String targetWord, String[] wordList) {
        int N = wordList.length;
        int M = startWord.length();
        HashSet<String> visited = new HashSet<>();
        Queue<String> q = new LinkedList<>();
        q.add(startWord);
        visited.add(startWord);
        while (!q.isEmpty()) {
            String currentWord = q.poll();
            if (currentWord.equals(targetWord)) {
                System.out.println(currentWord);
                return;
            }
            for (int i = 0; i < N; i++) {
                String word = wordList[i];
                if (!visited.contains(word)) {
                    int diff = 0;
                    for (int j = 0; j < M; j++) {
                        if (currentWord.charAt(j) != word.charAt(j)) {
                            diff++;
                        }
                    }
                    if (diff == 1) {
                        q.add(word);
                        visited.add(word);
                    }
                }
            }
        }
        System.out.println(-1);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine());
        while (T-- > 0) {
            String[] input = br.readLine().split(" ");
            String startWord = input[0];
            String targetWord = input[1];
            int N = Integer.parseInt(br.readLine());
            String[] wordList = br.readLine().split(" ");
            bfs(startWord, targetWord, wordList);
        }
    }
}

